// ===========================================
// Node: Get Current Day
// ===========================================
const tahitiTime = new Date().toLocaleString('en-US', {timeZone: 'Pacific/Tahiti'});
const now = new Date(tahitiTime);
// getDay() gives 0 for Sunday. We want 1=Monday...7=Sunday
const weekday = (now.getDay() === 0 ? 7 : now.getDay());

const dayTabMap = {
  1: 'Lundi', 2: 'Mardi', 3: 'Mercredi',
  4: 'Jeudi', 5: 'Vendredi', 6: 'Samedi'
};
const currentTab = dayTabMap[weekday] || null;

return [{
  json: {
    isWeekday:  !!currentTab,
    currentTab: currentTab,
    weekday:    weekday,
    dateStr:    (String(now.getDate()).padStart(2, '0') + '/' + String(now.getMonth() + 1).padStart(2, '0') + '/' + now.getFullYear())
  }
}];

const rows = $input.all();
const notifList = [];
for (const row of rows) {
  const r = row.json;
  if (r['ID Shopify'] === 'ID Shopify' || !r['ID Shopify']) continue;
  const phone = String(r['Téléphone'] || '').trim();
  const email = String(r['Email client'] || r['emailClient'] || r['Email'] || '').trim();
  if (!phone && !email) continue;
  const livraison = String(r['Livraison'] || '').trim();
  if (livraison !== 'Livraison en attente') continue;
  let phoneNorm = phone.replace(/[\s\-\(\)]/g, '');
  if (phoneNorm && !phoneNorm.startsWith('+')) {
    phoneNorm = phoneNorm.startsWith('689') ? '+' + phoneNorm : '+689' + phoneNorm;
  }
  const message = "Iaorana, notre livreur vous livrera aujourd'hui. "
    + "Il vous contactera directement par téléphone. "
    + "Le paiement se fera directement avec lui lors de la livraison. "
    + "Belle journée.";
  notifList.push({
    to:           phoneNorm,
    emailClient:  email || null,         // null si vide = Gmail ne plantera plus
    sendEmail:    !!email,              // true uniquement si email valide
    message:      message,
    client:       r['À CLIENT'] || 'Client',
    ref:          r['Réf commande'] || 'N/A',
    noNotif:      false                 // toujours défini → résout le bug "undefined"
  });
}
if (notifList.length === 0) {
  return [{ json: { noNotif: true, reason: 'Aucun client à contacter' } }];
}
return notifList.map(n => ({ json: n }));

// ============================================================
// Node: Check Notification Results
// WF2 - Vérifier si des envois ont échoué
// ============================================================
const items = $input.all();

const errors = [];
let successCount = 0;

for (const item of items) {
  const r = item.json;

  // Détection d'erreur : si n8n a ajouté un champ error (continueOnFail)
  const hasError = r.error
    || (r.http_code && r.http_code !== 200)
    || (r.response_code && r.response_code !== 'SUCCESS');

  if (hasError) {
    errors.push({
      client: r.client || 'Inconnu',
      to:     r.to || r.emailClient || 'N/A',
      error:  r.error?.message || r.response_code || 'Erreur inconnue'
    });
  } else {
    successCount++;
  }
}

return [{
  json: {
    hasErrors:    errors.length > 0,
    errorCount:   errors.length,
    successCount: successCount,
    totalNotif:   items.length,
    errorDetails: errors.length > 0
      ? errors.map(e => `${e.client} (${e.to}): ${e.error}`).join('\n')
      : '',
    summary: errors.length > 0
      ? `${errors.length} notification(s) échouée(s) sur ${items.length}`
      : `${successCount} notification(s) envoyée(s) avec succès`
  }
}];

